#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    const unsigned long long C = 1ULL << 59; // 2^59
    while(T--){
        unsigned long long N; scanf("%llu", &N);
        if(N==0){
            printf("-1\n");
        }else{
            unsigned long long a=1, b=2, d = C ^ N;
            printf("%llu %llu %llu %llu\n", a, b, C, d);
        }
    }
    return 0;
}

