#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    C = 1 << 59  # 2^59
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        if N == 0:
            out_lines.append("-1")
        else:
            a, b = 1, 2
            d = C ^ N
            out_lines.append(f"{a} {b} {C} {d}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

